import {provideCacheTracking} from 'inugami-ng/services';
import {UuidUtils} from 'inugami-ng/utils'

const APPLICATION = signal<string>('inu-showcase');
const ENV         = signal<string>('dev');
const SESSION_UID = signal<string>(UuidUtils.buildUid());
const VERSION     = signal<string>('0.0.0');

export const appConfig: ApplicationConfig = {
  providers: [
    provideCacheTracking({
                           env        : ENV,
                           sessionUid : SESSION_UID,
                           application: APPLICATION,
                           version    : VERSION
                         }),
    // ...
  ]
};


loadFormUrl(url: string) {

   const data = this.loadFormCache(url);
   if (data) {
     this.initSourceCode(data);
     return;
   }

   const cacheKey = `inu-code_${url}`;
   const pending = this.cache.getPending(cacheKey);

   if (pending) {
     pending.subscribe(res =>this.initSourceCode(res));
     return;
   }

   const request = this.http.get(url, {responseType: 'text'})
     .pipe(map(res => this.parseData(res, url)),
       tap(data => this.cache.set(cacheKey, data)),
       shareReplay(1)
     );
   this.cache.setPending(cacheKey, request);
   request.subscribe();

 }

  initSourceCode(data: SourceCode[]) {
    //...
  }


@Injectable({providedIn: 'root'})
export class InuCacheServices {

  public get<T>(key: string): T | undefined { }

  public getTTL<T>(key: string): T | undefined { }
}


@Injectable({providedIn: 'root'})
export class InuCacheServices {

  public getPending(key: string): Observable<any> | undefined { }

  public getPendingTTL(key: string): Observable<any> | undefined {  }
}


const cacheKey = `inu-code_${url}`;
const pending = this.cache.getPending(cacheKey);

if (pending) {
  pending.subscribe(res =>this.initSourceCode(res));
  return;
}
const request = this.http.get(url, {responseType: 'text'});
this.cache.setPending(cacheKey, request);


@Injectable({providedIn: 'root'})
export class InuCacheServices {

  public set(key: string, value: any): void { }

  public setTTL(key: string, value: any, ttl: number): void { }
}


const request = this.http.get(url, {responseType: 'text'})
      .pipe(map(res => this.parseData(res, url)),
        tap(data => this.cache.set(cacheKey, data)),
        shareReplay(1)
      );

this.cache.setPending(cacheKey, request);

request.subscribe();


@Injectable({providedIn: 'root'})
export class InuCacheServices {
  public clearKey(key : string) { }

  public clearKeyTTL(key : string) {  }

  public clear() { }
}
